import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"決済設定","description":"","frontmatter":{"title":"決済設定"},"headers":[],"relativePath":"tenant/21-stripe-full.md","filePath":"tenant/21-stripe-full.md"}'),l={name:"tenant/21-stripe-full.md"};function i(o,t,h,n,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_21-決済設定" tabindex="-1">21. 決済設定 <a class="header-anchor" href="#_21-決済設定" aria-label="Permalink to &quot;21. 決済設定&quot;">​</a></h1><p>決済設定では、POSLAの月額契約、お客様からのカード決済、カードリーダー、返金に関する設定を確認します。決済機能は店舗の売上に直接関わるため、営業開始前に必ずテストしてください。</p><h2 id="決済の種類" tabindex="-1">決済の種類 <a class="header-anchor" href="#決済の種類" aria-label="Permalink to &quot;決済の種類&quot;">​</a></h2><table tabindex="0"><thead><tr><th>種類</th><th>内容</th></tr></thead><tbody><tr><td>POSLA利用料</td><td>POSLAの月額利用料のお支払い</td></tr><tr><td>店舗のカード決済</td><td>お客様が店内またはオンラインで支払うカード決済</td></tr><tr><td>カードリーダー決済</td><td>POSレジと連携した対面カード決済</td></tr><tr><td>返金</td><td>会計後の返金処理</td></tr></tbody></table><h2 id="店舗側で確認すること" tabindex="-1">店舗側で確認すること <a class="header-anchor" href="#店舗側で確認すること" aria-label="Permalink to &quot;店舗側で確認すること&quot;">​</a></h2><ol><li>契約プランと請求先を確認します。</li><li>店舗で利用する決済方法を確認します。</li><li>カードリーダーを利用する場合は、接続とテスト決済を行います。</li><li>返金時の承認ルールを店舗内で決めます。</li><li>レジ締め時に決済金額とPOSLA上の売上を確認します。</li></ol><h2 id="カードリーダー利用時の注意" tabindex="-1">カードリーダー利用時の注意 <a class="header-anchor" href="#カードリーダー利用時の注意" aria-label="Permalink to &quot;カードリーダー利用時の注意&quot;">​</a></h2><ul><li>レジ端末とカードリーダーを同じネットワークで利用してください。</li><li>営業前に充電、接続、テスト決済を確認してください。</li><li>決済完了前に画面を閉じないでください。</li><li>エラーが出た場合は、二重決済になっていないか確認してください。</li></ul><h2 id="返金" tabindex="-1">返金 <a class="header-anchor" href="#返金" aria-label="Permalink to &quot;返金&quot;">​</a></h2><p>返金は店舗責任者の確認後に行ってください。返金理由、対象注文、返金額、担当者を記録しておくと、後日の確認がスムーズです。</p><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>決済が完了しない</td><td>カードリーダー、通信、カード状態を確認してください。</td></tr><tr><td>二重決済が心配</td><td>決済履歴を確認し、不明な場合はPOSLAサポートへお問い合わせください。</td></tr><tr><td>返金できない</td><td>権限、対象注文、決済状態を確認してください。</td></tr><tr><td>契約内容を確認したい</td><td>オーナー画面またはPOSLAサポートで確認してください。</td></tr></tbody></table>',12)])])}const b=a(l,[["render",i]]);export{u as __pageData,b as default};
